// Helper to get date for 2026
const getDateFor2026 = (month: number, day: number) => new Date(2026, month - 1, day);

// Generate ReligiousEvent objects from the compact saint entries
export const generateSaintsEvents2026 = (): ReligiousEvent[] => {
  return saintsCalendar.map(saint => ({
    id: `saint-${saint.month}-${saint.day}-2026`,
    name: saint.nameEn,
    nameFr: saint.nameFr,
    nameEn: saint.nameEn,
    description: saint.description,
    descriptionFr: saint.description,
    descriptionEn: saint.description,
    tradition: 'christianity' as const,
    date: getDateFor2026(saint.month, saint.day),
    isRecurring: true,
    color: '#D4AF37',
    subType: 'saint' as const,
    saintInfo: {
      patronOf: saint.patronOf,
      martyrOrConfessor: saint.type as 'martyr' | 'confesseur' | 'vierge' | 'docteur' | undefined
    }
  }));
};
